findings.codeql_raw_query:
/**
 * @name Verify cron string is embedded in parse exception messages
 * @description Confirm that the user-supplied cron string value is included in exception messages thrown by CronParser.parse
 * @kind path-problem
 * @problem.severity error
 * @id java/cron-parser-exception-user-input
 * @tags security
 *       external/cwe/cwe-917
 */
import java
import semmle.code.java.dataflow.TaintTracking

module ParseExceptionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The value parameter in CronParser.parse(String expression)
    exists(Method m, Parameter p |
      m.hasName("parse") and
      m.getDeclaringType().hasQualifiedName("com.cronutils.parser", "CronParser") and
      p = m.getParameter(0) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Any exception constructor argument in parse or called methods
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "Throwable") and
      sink.asExpr() = cie.getAnArgument()
    )
  }
}

module ParseExceptionFlow = TaintTracking::Global<ParseExceptionConfig>;
import ParseExceptionFlow::PathGraph

from ParseExceptionFlow::PathNode source, ParseExceptionFlow::PathNode sink
where ParseExceptionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User cron input flows into exception message from $@.", source.getNode(), "cron expression parameter"
